THOUGHT: The crash stems from SCEVExpander materializing TripCount/BECount after CFG splits in runtime unrolling, causing dominance/LCSSA issues for outer-loop values. I will fix this by hoisting the TripCount/BECount expansion to before the CFG is modified in LoopUnrollRuntime.cpp and removing the later duplicate expansion. Then I’ll verify by running the reproducer through opt with the runtime unroll pass and checking for verifier errors.

```bash
cd /llvm-autofix-deps/llvm/llvm && awk '
BEGIN { in_skip1=0; in_skip2=0; }
{
  # Replace the previously inserted (and now broken) hoist block with a correct one,
  # and skip all lines until the Loop structure comment.
  if ($0 ~ /\/\/ Hoist TripCount\/BECount expansion before CFG splits to maintain dominance/) {
    print $0;
    print "  IRBuilder<> BPre(PreHeaderBR);";
    print "  Value *TripCount = Expander.expandCodeFor(TripCountSC, TripCountSC->getType(), PreHeaderBR);";
    print "  Value *BECount;";
    print "  if ((!OtherExits.empty() || !SE->loopHasNoAbnormalExits(L)) &&";
    print "      !isGuaranteedNotToBeUndefOrPoison(TripCount, AC, PreHeaderBR, DT)) {";
    print "    TripCount = BPre.CreateFreeze(TripCount);";
    print "    BECount = BPre.CreateAdd(TripCount, Constant::getAllOnesValue(TripCount->getType()));";
    print "  } else {";
    print "    BECount = Expander.expandCodeFor(BECountSC, BECountSC->getType(), PreHeaderBR);";
    print "  }";
    in_skip1=1;
    next;
  }
  if (in_skip1) {
    if ($0 ~ /^  \/\/ Loop structure is the following:/) {
      print $0;
      in_skip1=0;
    }
    next;
  }
  # After PreHeaderBR builder creation later, drop the duplicate TripCount/BECount expansion
  # and resume printing at the first use (CreateTripRemainder).
  if ($0 ~ /^  IRBuilder<> B\(PreHeaderBR\);/) {
    print $0;
    in_skip2=1;
    next;
  }
  if (in_skip2) {
    if ($0 ~ /Value \* const ModVal = CreateTripRemainder/) {
      print $0;
      in_skip2=0;
    }
    next;
  }
  print $0;
}
' llvm/lib/Transforms/Utils/LoopUnrollRuntime.cpp > /tmp/LoopUnrollRuntime.cpp.fixed && mv /tmp/LoopUnrollRuntime.cpp.fixed llvm/lib/Transforms/Utils/LoopUnrollRuntime.cpp && cat <<'EOF' > /tmp/test.ll
define void @test(i1 %c, ptr %p) {
entry:
  br label %loop.1

loop.1:                                           ; preds = %loop.1, %entry
  %phi = phi ptr [ null, %entry ], [ %p, %loop.1 ]
  %load = load i64, ptr %p, align 8
  %add = add i64 %load, 1
  br i1 %c, label %if, label %loop.1

if:                                               ; preds = %loop.1
  %add.lcssa = phi i64 [ %add, %loop.1 ]
  %gep = getelementptr i64, ptr %p, i64 %add.lcssa
  br label %loop.2

loop.2:                                           ; preds = %loop.2, %if
  %iv = phi ptr [ %p, %if ], [ %iv.next, %loop.2 ]
  %iv.next = getelementptr i8, ptr %iv, i64 8
  %icmp = icmp eq ptr %iv, %gep
  br i1 %icmp, label %exit, label %loop.2

exit:                                             ; preds = %loop.2
  ret void
}
EOF
&& (bin/opt -S -passes='print<scalar-evolution>,loop-unroll' -unroll-runtime /tmp/test.ll -o /tmp/opt_out.ll 1>/dev/null 2>/tmp/opt_err.txt || true) \
&& if grep -Eq 'LLVM ERROR|Broken module|Instruction does not dominate' /tmp/opt_err.txt; then echo "FAIL: Verifier/Crash detected"; sed -n '1,120p' /tmp/opt_err.txt; else echo "PASS: No verifier errors after runtime unroll on reproducer"; fi
```

